mapper.select:
SELECT * FROM ( /* 1. 회사 설정 (시스템에 정의되지 않은 menu_id만) */ SELECT mi.menu_id, mi.menu_nm, mi.menu_lc, mi.menu_order, cmr.role_id, ri.role_nm, ri.role_security FROM comp_menu_role cmr INNER JOIN menu_info mi ON cmr.menu_id = mi.menu_id LEFT OUTER JOIN role_info ri ON ri.role_id = cmr.role_id WHERE cmr.comp_id = #{compId} AND mi.menu_gubun IN ('usr', 'adm') AND mi.menu_lc IS NOT NULL AND mi.menu_lc != '' AND cmr.menu_id NOT IN ( SELECT smr2.menu_id FROM system_menu_role smr2 INNER JOIN menu_info mi2 ON smr2.menu_id = mi2.menu_id WHERE mi2.menu_gubun IN ('usr', 'adm') )
UNION
/* 2. 시스템 설정 (usr, adm 메뉴) */ SELECT mi.menu_id, mi.menu_nm, mi.menu_lc, mi.menu_order, smr.role_id, ri.role_nm, ri.role_security FROM system_menu_role smr INNER JOIN menu_info mi ON smr.menu_id = mi.menu_id LEFT OUTER JOIN role_info ri ON ri.role_id = smr.role_id WHERE mi.menu_gubun IN ('usr', 'adm') AND mi.menu_lc IS NOT NULL AND mi.menu_lc != ''
UNION
/* 3. 시스템 전용 메뉴 (sys) - 항상 포함 */ SELECT mi.menu_id, mi.menu_nm, mi.menu_lc, mi.menu_order, smr.role_id, ri.role_nm, ri.role_security FROM system_menu_role smr INNER JOIN menu_info mi ON smr.menu_id = mi.menu_id LEFT OUTER JOIN role_info ri ON ri.role_id = smr.role_id WHERE mi.menu_gubun = 'sys' AND mi.menu_lc IS NOT NULL AND mi.menu_lc != '' ) t WHERE 1=1 ORDER BY menu_id ASC, role_id ASC
